     1|/**
     2| * IVX Business Opportunity Engine — Phase 4.
     3| *
     4| * Continuously searches for and scores business opportunities:
     5| *   - Investors and VC funds
     6| *   - Acquisition opportunities
     7| *   - Strategic partnerships
     8| *   - Distressed assets
     9| *   - Government programs and grants
    10| *   - Enterprise customers
    11| *   - Commercial real estate opportunities
    12| *
    13| * Every opportunity is scored on:
    14| *   - Strategic fit (1–10)
    15| *   - Revenue potential (estimated)
    16| *   - Time to close (days estimate)
    17| *   - Risk level (low/medium/high)
    18| *   - Resource requirement (low/medium/high)
    19| *
    20| * HARD HONESTY RULES:
    21| *   - Revenue estimates are marked as estimates, never promises.
    22| *   - Empty search results are reported honestly.
    23| *   - No opportunity is fabricated.
    24| *   - All scores are grounded in available data.
    25| */
    26|import { appendFile, mkdir, readFile, rename, writeFile } from 'node:fs/promises';
    27|import path from 'node:path';
    28|
    29|export const IVX_OPPORTUNITY_ENGINE_MARKER = 'ivx-opportunity-engine-2026-07-01';
    30|
    31|// ── Types ──────────────────────────────────────────────────────────────────
    32|
    33|export type OpportunityType =
    34|  | 'investor'
    35|  | 'acquisition'
    36|  | 'partnership'
    37|  | 'distressed_asset'
    38|  | 'government_grant'
    39|  | 'enterprise_customer'
    40|  | 'commercial_real_estate';
    41|
    42|export const OPPORTUNITY_TYPES: readonly OpportunityType[] = [
    43|  'investor',
    44|  'acquisition',
    45|  'partnership',
    46|  'distressed_asset',
    47|  'government_grant',
    48|  'enterprise_customer',
    49|  'commercial_real_estate',
    50|];
    51|
    52|export type OpportunityRisk = 'low' | 'medium' | 'high';
    53|
    54|export type OpportunityScore = {
    55|  strategicFit: number;       // 1–10
    56|  revenuePotential: string;   // estimated range
    57|  timeToCloseDays: number;    // estimated days
    58|  risk: OpportunityRisk;
    59|  resourceRequirement: 'low' | 'medium' | 'high';
    60|  totalScore: number;         // 0–100 composite
    61|};
    62|
    63|export type BusinessOpportunity = {
    64|  id: string;
    65|  type: OpportunityType;
    66|  title: string;
    67|  description: string;
    68|  source: string;
    69|  sourceUrl: string;
    70|  discoveredAt: string;
    71|  score: OpportunityScore;
    72|  status: 'new' | 'researching' | 'contacted' | 'in_discussion' | 'closed_won' | 'closed_lost' | 'archived';
    73|  nextAction: string;
    74|  notes: string;
    75|};
    76|
    77|export type OpportunityReport = {
    78|  id: string;
    79|  generatedAt: string;
    80|  totalOpportunities: number;
    81|  byType: Record<OpportunityType, number>;
    82|  topOpportunities: BusinessOpportunity[];
    83|  scoreDistribution: { high: number; medium: number; low: number };
    84|  summary: string;
    85|};
    86|
    87|export type OpportunityEngineState = {
    88|  marker: string;
    89|  lastRunAt: string | null;
    90|  nextRunAt: string | null;
    91|  runCount: number;
    92|  totalDiscovered: number;
    93|  activeOpportunities: number;
    94|  opportunities: BusinessOpportunity[];
    95|  reports: OpportunityReport[];
    96|  enabled: boolean;
    97|};
    98|
    99|// ── Scoring ────────────────────────────────────────────────────────────────
   100|
   101|function calculateTotalScore(
   102|  strategicFit: number,
   103|  timeToCloseDays: number,
   104|  risk: OpportunityRisk,
   105|): number {
   106|  // Strategic fit: 0–40 points
   107|  const fitScore = Math.max(0, Math.min(10, strategicFit)) * 4;
   108|
   109|  // Time to close: faster = better, 0–30 points
   110|  const timeScore = Math.max(0, 30 - Math.min(timeToCloseDays, 365) * (30 / 365));
   111|
   112|  // Risk: low=30, medium=15, high=5
   113|  const riskScore = risk === 'low' ? 30 : risk === 'medium' ? 15 : 5;
   114|
   115|  return Math.round(fitScore + timeScore + riskScore);
   116|}
   117|
   118|// ── Durable State ──────────────────────────────────────────────────────────
   119|
   120|const STATE_DIR = path.join(process.cwd(), 'logs', 'audit', 'opportunity-engine');
   121|const STATE_FILE = path.join(STATE_DIR, 'state.json');
   122|const OPPORTUNITIES_FILE = path.join(STATE_DIR, 'opportunities.jsonl');
   123|const REPORTS_DIR = path.join(STATE_DIR, 'reports');
   124|
   125|let _state: OpportunityEngineState | null = null;
   126|
   127|async function ensureDirs(): Promise<void> {
   128|  await mkdir(STATE_DIR, { recursive: true });
   129|  await mkdir(REPORTS_DIR, { recursive: true });
   130|}
   131|
   132|function defaultState(): OpportunityEngineState {
   133|  return {
   134|    marker: IVX_OPPORTUNITY_ENGINE_MARKER,
   135|    lastRunAt: null,
   136|    nextRunAt: new Date(Date.now() + 24 * 60 * 60 * 1000).toISOString(),
   137|    runCount: 0,
   138|    totalDiscovered: 0,
   139|    activeOpportunities: 0,
   140|    opportunities: [],
   141|    reports: [],
   142|    enabled: true,
   143|  };
   144|}
   145|
   146|async function loadState(): Promise<OpportunityEngineState> {
   147|  if (_state) return _state;
   148|  await ensureDirs();
   149|  try {
   150|    const raw = await readFile(STATE_FILE, 'utf-8');
   151|    const parsed = JSON.parse(raw) as OpportunityEngineState;
   152|    if (parsed.marker === IVX_OPPORTUNITY_ENGINE_MARKER) {
   153|      _state = parsed;
   154|      return _state;
   155|    }
   156|  } catch { /* first run */ }
   157|  _state = defaultState();
   158|  await persistState();
   159|  return _state;
   160|}
   161|
   162|async function persistState(): Promise<void> {
   163|  if (!_state) return;
   164|  await ensureDirs();
   165|  const tmp = STATE_FILE + '.tmp';
   166|  await writeFile(tmp, JSON.stringify(_state, null, 2), 'utf-8');
   167|  await rename(tmp, STATE_FILE);
   168|}
