   170|// ── Core Engine Logic ──────────────────────────────────────────────────────
   171|
   172|/**
   173| * Create a new business opportunity.
   174| */
   175|export function createOpportunity(
   176|  type: OpportunityType,
   177|  title: string,
   178|  description: string,
   179|  source: string,
   180|  sourceUrl: string,
   181|  strategicFit: number = 5,
   182|  revenuePotential: string = 'Unknown',
   183|  timeToCloseDays: number = 90,
   184|  risk: OpportunityRisk = 'medium',
   185|  resourceRequirement: 'low' | 'medium' | 'high' = 'medium',
   186|): BusinessOpportunity {
   187|  const totalScore = calculateTotalScore(strategicFit, timeToCloseDays, risk);
   188|
   189|  return {
   190|    id: `opp-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
   191|    type,
   192|    title,
   193|    description,
   194|    source,
   195|    sourceUrl,
   196|    discoveredAt: new Date().toISOString(),
   197|    score: {
   198|      strategicFit: Math.max(1, Math.min(10, strategicFit)),
   199|      revenuePotential,
   200|      timeToCloseDays: Math.max(1, timeToCloseDays),
   201|      risk,
   202|      resourceRequirement,
   203|      totalScore,
   204|    },
   205|    status: 'new',
   206|    nextAction: 'Research and validate',
   207|    notes: '',
   208|  };
   209|}
   210|
   211|/**
   212| * Add opportunities to the engine.
   213| */
   214|export async function addOpportunities(
   215|  opportunities: BusinessOpportunity[],
   216|): Promise<OpportunityReport> {
   217|  const state = await loadState();
   218|  state.opportunities.push(...opportunities);
   219|  state.totalDiscovered += opportunities.length;
   220|  state.activeOpportunities = state.opportunities.filter(
   221|    (o) => !['closed_won', 'closed_lost', 'archived'].includes(o.status),
   222|  ).length;
   223|
   224|  // Persist to opportunities log
   225|  await ensureDirs();
   226|  for (const opp of opportunities) {
   227|    await appendFile(OPPORTUNITIES_FILE, JSON.stringify(opp) + '\n', 'utf-8');
   228|  }
   229|
   230|  const report = generateOpportunityReport(state.opportunities);
   231|  state.reports.unshift(report);
   232|  if (state.reports.length > 30) state.reports = state.reports.slice(0, 30);
   233|
   234|  state.lastRunAt = new Date().toISOString();
   235|  state.nextRunAt = new Date(Date.now() + 24 * 60 * 60 * 1000).toISOString();
   236|  state.runCount++;
   237|  await persistState();
   238|
   239|  // Persist report
   240|  const reportFile = path.join(REPORTS_DIR, `${report.id}.json`);
   241|  await writeFile(reportFile, JSON.stringify(report, null, 2), 'utf-8');
   242|
   243|  return report;
   244|}
   245|
   246|/**
   247| * Generate a report from current opportunities.
   248| */
   249|function generateOpportunityReport(opportunities: BusinessOpportunity[]): OpportunityReport {
   250|  const scored = [...opportunities].sort(
   251|    (a, b) => b.score.totalScore - a.score.totalScore,
   252|  );
   253|
   254|  const topOpportunities = scored.slice(0, 10);
   255|
   256|  const byType = {} as Record<OpportunityType, number>;
   257|  for (const t of OPPORTUNITY_TYPES) byType[t] = 0;
   258|  for (const opp of opportunities) byType[opp.type]++;
   259|
   260|  const scoreDistribution = {
   261|    high: scored.filter((o) => o.score.totalScore >= 70).length,
   262|    medium: scored.filter((o) => o.score.totalScore >= 40 && o.score.totalScore < 70).length,
   263|    low: scored.filter((o) => o.score.totalScore < 40).length,
   264|  };
   265|
   266|  return {
   267|    id: `or-${Date.now()}`,
   268|    generatedAt: new Date().toISOString(),
   269|    totalOpportunities: opportunities.length,
   270|    byType,
   271|    topOpportunities,
   272|    scoreDistribution,
   273|    summary: `${opportunities.length} total opportunities. Top: ${topOpportunities.slice(0, 3).map((o) => o.title).join(' | ')}`,
   274|  };
   275|}
   276|
   277|/**
   278| * Update an opportunity's status.
   279| */
   280|export async function updateOpportunityStatus(
   281|  opportunityId: string,
   282|  status: BusinessOpportunity['status'],
   283|  notes?: string,
   284|): Promise<BusinessOpportunity | null> {
   285|  const state = await loadState();
   286|  const opp = state.opportunities.find((o) => o.id === opportunityId);
   287|  if (!opp) return null;
   288|  opp.status = status;
   289|  if (notes !== undefined) opp.notes = notes;
   290|  state.activeOpportunities = state.opportunities.filter(
   291|    (o) => !['closed_won', 'closed_lost', 'archived'].includes(o.status),
   292|  ).length;
   293|  await persistState();
   294|  return opp;
   295|}
   296|
   297|/**
   298| * Get the current engine state.
   299| */
   300|export async function getOpportunityState(): Promise<OpportunityEngineState> {
   301|  return loadState();
   302|}
   303|
   304|/**
   305| * Get top opportunities by score.
   306| */
   307|export async function getTopOpportunities(limit: number = 10): Promise<BusinessOpportunity[]> {
   308|  const state = await loadState();
   309|  return [...state.opportunities]
   310|    .filter((o) => !['closed_lost', 'archived'].includes(o.status))
   311|    .sort((a, b) => b.score.totalScore - a.score.totalScore)
   312|    .slice(0, limit);
   313|}
   314|
   315|/**
   316| * Get opportunities by type.
   317| */
   318|export async function getOpportunitiesByType(
   319|  type: OpportunityType,
   320|): Promise<BusinessOpportunity[]> {
   321|  const state = await loadState();
   322|  return state.opportunities
   323|    .filter((o) => o.type === type)
   324|    .sort((a, b) => b.score.totalScore - a.score.totalScore);
   325|}
   326|
   327|// ── Opportunity Type Labels ────────────────────────────────────────────────
   328|
   329|export function getOpportunityTypeLabels(): Record<OpportunityType, string> {
   330|  return {
   331|    investor: 'Investor / VC',
   332|    acquisition: 'Acquisition Target',
   333|    partnership: 'Strategic Partnership',
   334|    distressed_asset: 'Distressed Asset',
   335|    government_grant: 'Government Grant / Program',
   336|    enterprise_customer: 'Enterprise Customer',
   337|    commercial_real_estate: 'Commercial Real Estate',
   338|  };
   339|}
   340|
   341|// ── Validation ─────────────────────────────────────────────────────────────
   342|
   343|export async function validateOpportunityEngine(): Promise<{ valid: boolean; issues: string[] }> {
   344|  const state = await loadState();
   345|  const issues: string[] = [];
   346|  if (state.marker !== IVX_OPPORTUNITY_ENGINE_MARKER) issues.push('State marker mismatch');
   347|  return { valid: issues.length === 0, issues };
