   213|/**
   214| * Prioritize the task queue by urgency and dependency resolution.
   215| * Critical tasks always come first. Then high/medium/low by creation time.
   216| * Tasks whose dependencies are unmet are pushed down.
   217| */
   218|function prioritizeQueue(tasks: OrchestratedTask[]): OrchestratedTask[] {
   219|  const priorityWeight: Record<OrchestratorPriority, number> = {
   220|    critical: 0,
   221|    high: 1,
   222|    medium: 2,
   223|    low: 3,
   224|    idle: 4,
   225|  };
   226|
   227|  const completedIds = new Set(
   228|    tasks.filter((t) => t.status === 'completed').map((t) => t.id),
   229|  );
   230|
   231|  return [...tasks].sort((a, b) => {
   232|    const aBlocked = a.dependencies.some((d) => !completedIds.has(d));
   233|    const bBlocked = b.dependencies.some((d) => !completedIds.has(d));
   234|    if (aBlocked && !bBlocked) return 1;
   235|    if (!aBlocked && bBlocked) return -1;
   236|    const pw = priorityWeight[a.priority] - priorityWeight[b.priority];
   237|    if (pw !== 0) return pw;
   238|    return new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime();
   239|  });
   240|}
