   246|export async function dispatchNextTask(): Promise<OrchestratedTask | null> {
   247|  const state = await loadState();
   248|  const completedIds = new Set(
   249|    state.taskQueue.filter((t) => t.status === 'completed').map((t) => t.id),
   250|  );
   251|  const runningCount = state.taskQueue.filter((t) => t.status === 'running').length;
