   257|      t.status === 'pending' &&
   258|      t.dependencies.every((d) => completedIds.has(d)),
   259|  );
   260|
   261|  if (next) {
   262|    next.status = 'running';
   263|    next.startedAt = new Date().toISOString();
   264|    await persistState();
   265|    await appendTaskLog(next);
   266|  }
