   425|export async function runOrchestratorCycle(): Promise<{
   426|  blockersFound: number;
   427|  recovered: number;
   428|  dispatched: number;
   429|  cycleCount: number;
   430|}> {
   431|  const state = await loadState();
   432|  state.cycleCount++;
   433|  state.lastCycleAt = new Date().toISOString();
   434|
   435|  // 1. Detect blockers
   436|  const blockers = await detectBlockers();
   437|  let recovered = 0;
   438|  if (state.autoRecoverEnabled) {
   439|    for (const blocker of blockers) {
   440|      const result = await recoverTask(blocker.id);
   441|      if (result && result.action !== 'escalate') recovered++;
   442|    }
   443|  }
   444|
   445|  // 2. Dispatch next ready task
   446|  const dispatched = await dispatchNextTask();
   447|
   448|  state.updatedAt = new Date().toISOString();
   449|  await persistState();
   450|
   451|  return {
   452|    blockersFound: blockers.length,
   453|    recovered,
   454|    dispatched: dispatched ? 1 : 0,
   455|    cycleCount: state.cycleCount,
   456|  };
