   195|/**
   196| * Search memory by keyword or category.
   197| */
   198|export async function searchMemory(
   199|  query: string,
   200|  options?: {
   201|    category?: MemoryCategory;
   202|    limit?: number;
   203|    includeDeprecated?: boolean;
   204|  },
   205|): Promise<MemorySearchResult[]> {
   206|  const entries = await loadEntries();
   207|  const lowerQuery = query.toLowerCase();
   208|  const queryWords = lowerQuery.split(/\s+/).filter((w) => w.length > 0);
   209|
   210|  const results: MemorySearchResult[] = [];
   211|
   212|  for (const entry of entries) {
   213|    if (options?.category && entry.category !== options.category) continue;
   214|    if (!options?.includeDeprecated && entry.deprecated) continue;
   215|
   216|    // Score by keyword match in title, content, tags
   217|    let score = 0;
   218|    const searchText = `${entry.title} ${entry.content} ${entry.tags.join(' ')}`.toLowerCase();
   219|    for (const word of queryWords) {
   220|      if (searchText.includes(word)) score += 10;
   221|    }
   222|    if (entry.title.toLowerCase().includes(lowerQuery)) score += 25;
   223|    if (entry.tags.some((t) => t.toLowerCase().includes(lowerQuery))) score += 15;
   224|
   225|    if (score > 0) {
   226|      results.push({ entry, relevanceScore: score });
   227|    }
   228|  }
   229|
   230|  return results
   231|    .sort((a, b) => b.relevanceScore - a.relevanceScore)
   232|    .slice(0, options?.limit ?? 20);
   233|}
