   137|export async function generateExecutiveReport(): Promise<ExecutiveReport> {
   138|  const state = await loadState();
   139|  const now = new Date().toISOString();
   140|
   141|  // Gather all subsystem data defensively — one failure doesn't block the report
   142|  let kpis: Awaited<ReturnType<typeof getExecutiveKPIs>> | null = null;
   143|  let orchState: Awaited<ReturnType<typeof getOrchestratorState>> | null = null;
   144|  let researchState: Awaited<ReturnType<typeof getResearchState>> | null = null;
   145|  let researchReport: Awaited<ReturnType<typeof getLatestResearchReport>> | null = null;
   146|  let oppState: Awaited<ReturnType<typeof getOpportunityState>> | null = null;
   147|  let topOpps: Awaited<ReturnType<typeof getTopOpportunities>> | null = null;
   148|  let impState: Awaited<ReturnType<typeof getSelfImprovementState>> | null = null;
   149|  let openTasks: Awaited<ReturnType<typeof getOpenTasks>> | null = null;
   150|  let memState: Awaited<ReturnType<typeof getMemoryState>> | null = null;
   151|  let recentMem: Awaited<ReturnType<typeof getRecentMemories>> | null = null;
   152|  let govState: Awaited<ReturnType<typeof getGovernanceState>> | null = null;
   153|  let recentAudit: Awaited<ReturnType<typeof getRecentAudit>> | null = null;
   154|
