   156|  try { orchState = await getOrchestratorState(); } catch { /* continue */ }
   157|  try { researchState = await getResearchState(); } catch { /* continue */ }
   158|  try { researchReport = await getLatestResearchReport(); } catch { /* continue */ }
   159|  try { oppState = await getOpportunityState(); } catch { /* continue */ }
   160|  try { topOpps = await getTopOpportunities(5); } catch { /* continue */ }
   161|  try { impState = await getSelfImprovementState(); } catch { /* continue */ }
   162|  try { openTasks = await getOpenTasks(); } catch { /* continue */ }
   163|  try { memState = await getMemoryState(); } catch { /* continue */ }
   164|  try { recentMem = await getRecentMemories(10); } catch { /* continue */ }
   165|  try { govState = await getGovernanceState(); } catch { /* continue */ }
   166|  try { recentAudit = await getRecentAudit(10); } catch { /* continue */ }
   167|
   168|  // Build engineering section
   169|  const engineering: EngineeringSection = {
   170|    completedWork: {
   171|      count: kpis?.completedTasks ?? 0,
   172|      items: orchState?.taskQueue
   173|        .filter((t) => t.status === 'completed')
   174|        .slice(0, 5)
   175|        .map((t) => t.goal) ?? [],
   176|    },
   177|    activeDeployments: {
   178|      count: 0,
   179|      latestSha: null,
   180|      latestDeployAt: null,
   181|    },
   182|    blockers: {
   183|      count: kpis?.blockedTasks ?? 0,
   184|      items: orchState?.taskQueue
   185|        .filter((t) => t.status === 'blocked')
   186|        .slice(0, 5)
   187|        .map((t) => t.goal) ?? [],
   188|    },
   189|    health: {
   190|      healthySubsystems: kpis?.healthySubsystems ?? 0,
   191|      degradedSubsystems: kpis?.degradedSubsystems ?? 0,
   192|      unreachableSubsystems: kpis?.unreachableSubsystems ?? 0,
   193|    },
   194|    openImprovementTasks: openTasks?.length ?? 0,
   195|  };
   196|
   197|  // Build business section
   198|  const business: BusinessSection = {
   199|    newOpportunities: {
   200|      total: oppState?.totalDiscovered ?? 0,
   201|      topItems: topOpps?.slice(0, 3).map((o) => `${o.title} (score: ${o.score.totalScore})`) ?? [],
   202|    },
   203|    investorLeads: {
   204|      count: topOpps?.filter((o) => o.type === 'investor').length ?? 0,
   205|      topItems: topOpps?.filter((o) => o.type === 'investor').slice(0, 3).map((o) => o.title) ?? [],
   206|    },
   207|    marketIntelligence: {
   208|      findings: researchState?.totalFindings ?? 0,
   209|      topItems: researchReport?.topOpportunities?.slice(0, 3).map((f) => f.title) ?? [],
   210|    },
   211|    technologyDiscoveries: {
   212|      findings: researchReport?.technologiesWorthAdopting?.length ?? 0,
   213|      topItems: researchReport?.technologiesWorthAdopting?.slice(0, 3).map((f) => f.title) ?? [],
   214|    },
   215|  };
   216|
   217|  // Build AI section
   218|  const aiFindings = researchReport?.findings ?? [];
   219|  const modelFindings = aiFindings.filter((f) => f.domain === 'ai_models');
   220|  const frameworkFindings = aiFindings.filter((f) => f.domain === 'enterprise_software');
   221|
   222|  const ai: AISection = {
   223|    newModels: {
   224|      count: modelFindings.length,
   225|      items: modelFindings.slice(0, 3).map((f) => f.title),
   226|    },
   227|    newFrameworks: {
   228|      count: frameworkFindings.length,
   229|      items: frameworkFindings.slice(0, 3).map((f) => f.title),
   230|    },
   231|    recommendedUpgrades: {
   232|      count: researchReport?.technologiesWorthAdopting?.length ?? 0,
   233|      items: researchReport?.technologiesWorthAdopting?.slice(0, 3).map((f) => f.title) ?? [],
   234|    },
   235|  };
   236|
   237|  // Build governance section
   238|  const governance = {
   239|    totalActions: govState?.totalActions ?? 0,
   240|    pendingApprovals: govState?.pendingCount ?? 0,
   241|    recentAuditEntries: recentAudit?.length ?? 0,
   242|  };
   243|
   244|  // Build memory section
   245|  const memory = {
   246|    totalEntries: memState?.totalEntries ?? 0,
   247|    recentInsights: recentMem?.slice(0, 3).map((m) => m.title) ?? [],
   248|  };
   249|
   250|  // Compose report
   251|  const report: ExecutiveReport = {
   252|    id: `er-${Date.now()}`,
   253|    generatedAt: now,
   254|    reportNumber: state.totalReports + 1,
   255|    engineering,
   256|    business,
   257|    ai,
   258|    governance,
   259|    memory,
   260|    summary: `Executive Report #${state.totalReports + 1}: ${engineering.health.healthySubsystems}/${(engineering.health.healthySubsystems + engineering.health.degradedSubsystems + engineering.health.unreachableSubsystems) || '?'} subsystems healthy. ${business.newOpportunities.total} opportunities. ${ai.newModels.count + ai.newFrameworks.count} AI discoveries.`,
   261|    disclaimer: DISCLAIMER,
   262|  };
   263|
   264|  // Persist report
   265|  await ensureDirs();
   266|  const reportFile = path.join(REPORTS_DIR, `${report.id}.json`);
   267|  await writeFile(reportFile, JSON.stringify(report, null, 2), 'utf-8');
   268|
   269|  // Update index
   270|  const indexFile = path.join(REPORTS_DIR, 'index.jsonl');
   271|  await appendFile(indexFile, JSON.stringify({ id: report.id, at: now, number: report.reportNumber }) + '\n', 'utf-8');
   272|
   273|  // Update state
   274|  state.lastGeneratedAt = now;
   275|  state.nextGenerationAt = new Date(Date.now() + state.intervalHours * 60 * 60 * 1000).toISOString();
   276|  state.totalReports++;
   277|  await persistState();
   278|
   279|  return report;
   280|}
